import React, { useState, useEffect } from 'react';
import './styles/App.css';
import Terminal from './functions/Terminal';
import Box from './functions/Box';
import ResumeContent from './functions/ResumeContent';
import GitHubWidget from './widgets/github/github-widget';
import 'github-widget/dist/style.css';

const App = () => {
  const [activeApp, setActiveApp] = useState(null);
  const [activeTab, setActiveTab] = useState(null);

  useEffect(() => {

  }, []);

  const handleBoxClick = (boxName) => {
    setActiveApp(boxName);
    setActiveTab(null); // Reset active tab when a new box is clicked
  };

  const box1Text = activeApp === 'box1' ? 'Scroll Down!' : 'About Me';
  const box2Text = activeApp === 'box2' ? 'Scroll Down!' : 'Projects';
  const box3Text = activeApp === 'box3' ? 'Scroll Down!' : 'Resume';

  let content = null;

  if (activeApp === 'box3') {
    content = <ResumeContent />;
  }

  return (
    <div className="App">
      <header className="App-header">
        <Terminal activeApp={activeApp} />
        <div className="box-container">
          <Box
            active={activeApp === 'box1'}
            boxText={box1Text}
            onClick={() => handleBoxClick('box1')}
          >
            {activeApp !== 'box1' && 'My Backstory'}
          </Box>
          <Box
            active={activeApp === 'box2'}
            boxText={box2Text}
            onClick={() => handleBoxClick('box2')}
          >
            {activeApp !== 'box2' && 'Past, Current, and Future Projects'}
          </Box>
          <Box
            active={activeApp === 'box3'}
            boxText={box3Text}
            onClick={() => handleBoxClick('box3')}
          >
            {activeApp !== 'box3' && 'My Resume'}
          </Box>
        </div>
        {activeApp && (
          <div className="text-container">
            {activeApp === 'box2' && (
              <div className="tab-container">
                <div
                  className={`tab ${activeTab === 'tab1' && 'active'}`}
                  onClick={() => setActiveTab('tab1')}
                >
                  Tab 1
                </div>
                <div
                  className={`tab ${activeTab === 'tab2' && 'active'}`}
                  onClick={() => setActiveTab('tab2')}
                >
                  Tab 2
                </div>
                <div
                  className={`tab ${activeTab === 'tab3' && 'active'}`}
                  onClick={() => setActiveTab('tab3')}
                >
                  Tab 3
                </div>
                <div
                  className={`tab ${activeTab === 'tab4' && 'active'}`}
                  onClick={() => setActiveTab('tab4')}
                >
                  Tab 4
                </div>
                <div
                  className={`tab ${activeTab === 'tab5' && 'active'}`}
                  onClick={() => setActiveTab('tab5')}
                >
                  Tab 5
                </div>
                <div
                  className={`tab ${activeTab === 'tab6' && 'active'}`}
                  onClick={() => setActiveTab('tab6')}
                >
                  Github
                </div>
              </div>
            )}
            {activeTab === 'tab6' && (
              <div className="github-widget-container">
                <GitHubWidget user="qNateYT" height="400" />
              </div>
            )}
          </div>
        )}
      </header>
    </div>
  );
};

export default App;
